  governing_guidelines = 'NRA Range Source Book (range design and operations); NSSF (National Shooting Sports Foundation) Range Development Standards; OSHA General Duty Clause (29 USC 654(a)(1)); 27 CFR Part 478 (ATF firearms regulations applicability to ranges); EPA lead management per RCRA and TSCA (lead contamination at shooting ranges); state/local range regulations; Cal. Penal Code 25550-25700 (discharge of firearms restrictions); NIOSH lead exposure controls; SAAMI (Sporting Arms and Ammunition Manufacturers'' Institute) safety guidelines',
  standards_of_creation = 'NRA Range Source Book design criteria (backstop, baffles, berms, surface danger zone); range Standard Operating Procedures (SOP); range rules and user agreement documentation; lead management plan per EPA best management practices for lead at outdoor shooting ranges; ventilation system documentation for indoor ranges per NIOSH guidelines; instructor/RSO qualification documentation per NRA RSO certification; emergency action plan; liability waiver and informed consent; ammunition restrictions documentation; range inspection and maintenance schedule',
  soc_controls = 'Daily range safety inspection before operations; RSO certification currency (NRA RSO certification renewal); lead monitoring per OSHA (29 CFR 1910.1025 for general industry; 29 CFR 1926.62 for construction); environmental lead management (soil sampling, stormwater runoff monitoring per RCRA); range SOP compliance verification; incident/accident reporting and investigation; noise monitoring per 29 CFR 1910.95; ammunition type restrictions enforcement; backstop/berm integrity inspection; air quality monitoring for indoor ranges per OSHA PEL and NIOSH REL; liability insurance coverage verification'
